import{_ as n,I as e,o as p,c as o,at as l,J as t}from"./chunks/framework.DYZFTu11.js";const u=JSON.parse('{"title":"α星大屠杀","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/events/alpha-star-massacre.md","filePath":"zh_cn/events/alpha-star-massacre.md","lastUpdated":1773498699000}'),i={name:"zh_cn/events/alpha-star-massacre.md"};function h(c,a,d,_,m,b){const r=e("NolebaseGitContributors"),s=e("NolebaseGitChangelog");return p(),o("div",null,[a[0]||(a[0]=l('<h1 id="α星大屠杀" tabindex="-1">α星大屠杀 <a class="header-anchor" href="#α星大屠杀" aria-label="Permalink to “α星大屠杀”">​</a></h1><p>在星海的编年史中，鲜有事件能像“α星大屠杀”那样，以如此惨烈和决绝的方式，宣告一个旧时代的终结与一个新势力的血腥诞生。这场发生于2062年末的冲突，不仅是灵裔一族挣脱枷锁的怒吼，更是曾经不可一世的商业财团走向崩溃的序曲。它如同一道深刻的伤疤，永远铭刻在历史的卷册之上，警示着后人——当长久的压迫遭遇复仇的狂热时，文明的脆弱将暴露无遗。</p><h2 id="风暴前夜-静谧的杀机" tabindex="-1">风暴前夜：静谧的杀机 <a class="header-anchor" href="#风暴前夜-静谧的杀机" aria-label="Permalink to “风暴前夜：静谧的杀机”">​</a></h2><p>自星源——那位被后世誉为“灵裔统一者”的非凡领袖——出现后，散落于诅咒之地、彼此隔阂的灵裔各族，仿佛找到了失落已久的灵魂核心，再度凝聚成一个整体。在星源的意志下，复仇的火焰被暂时抑制，转化为一股在阴影中悄然滋长的庞大军事力量。灵裔的社会进入了一种奇异的静默期，他们在黑暗中磨砺爪牙，耐心等待着走出那片被诅咒的故土，向整个星系宣告他们回归的时刻。</p><p>然而，即便是最严密的隐藏，也无法完全隔绝气息的泄露。财团设在诅咒之地周边的前哨实验室，如同敏感的触须，隐约感知到了地表之下正在积蓄的能量。作为回应，财团增派了更多的α星防卫军舰队与地面部队，加强了对诅咒之地边界的巡逻与封锁。他们自以为这能将威胁扼杀于摇篮，却未曾料到，这看似严密的布防，反而为灵裔的渗透计划创造了绝佳的掩护与机会。</p><p>历史的转折点，于2062年12月3日，α星当地时间23:30分悄然来临。一支由灵裔中最顶尖的潜行与渗透专家组成的“幽影”小队，如鬼魅般穿过了财团的侦测网络，抵达了α星上一处早已废弃的星球防御系统控制枢纽。这座冰冷的钢铁巨兽曾是财团统治的象征，如今却将在仇敌手中复苏。小队利用从财团窃取的核心技术，并结合了神秘“归家者”所流传出的部分科技，夜以继日地进行修复。当第二天清晨的第一缕阳光照亮枢纽的轮廓时，沉睡了数十年的轨道火炮系统被成功激活。一柄足以封锁整个近地轨道的达摩克利斯之剑，已然悬于所有α星居民的头顶，静待屠杀指令的下达。</p><h3 id="赤潮降临-屠杀的开端" tabindex="-1">赤潮降临：屠杀的开端 <a class="header-anchor" href="#赤潮降临-屠杀的开端" aria-label="Permalink to “赤潮降临：屠杀的开端”">​</a></h3><p>2062年12月4日，一个将被α星幸存者永远铭记的末日。当地时间12:30分，灵裔主力军团如决堤的洪流，从诅咒之地的阴影中倾巢而出，对财团的核心实验室发起了闪电般的猛攻。财团的防御部队在这场蓄谋已久的突袭面前猝不及防，仅仅半个小时，这座象征着财团技术与权力的堡垒便宣告陷落。</p><p>这仅仅是序幕。当财团调集α星防卫军主力前往探查实验室状况，试图夺回失地时，灵裔真正的杀招才显现出来。遍布α星各主要城市的隐秘传送门被同时激活，无数灵裔战士从中涌出，将战争瞬间从偏远的边境引爆至繁华的腹心。</p><p>屠杀，就此开始。</p><p>在接下来的不到两个小时里，α星的天空被染成了血红色。长久被压抑的仇恨与复仇的狂喜，彻底吞噬了基层灵裔战士的理智。星源下达的“优先打击军事目标，避免波及平民”的命令被完全抛诸脑后。战争的野兽挣脱了最后的枷锁，无组织、无纪律的灵裔部队将武器对准了手无寸铁的平民。城市化为了血肉磨坊，尖叫与哀嚎取代了往日的喧嚣。α星防卫军尝试组织有效的抵抗，但在灵裔排山倒海的数量优势下，他们的防线被一次又一次地撕碎、击溃。整个星球的指挥系统在极短时间内陷入瘫痪。</p><h2 id="环形山的回响-最后的抵抗与神秘的-归家者" tabindex="-1">环形山的回响：最后的抵抗与神秘的“归家者” <a class="header-anchor" href="#环形山的回响-最后的抵抗与神秘的-归家者" aria-label="Permalink to “环形山的回响：最后的抵抗与神秘的“归家者””">​</a></h2><p>在一片混乱与绝望之中，仍有英雄挺身而出。少数幸存的α星防卫军军官和士兵，没有选择徒劳的殉死，而是迅速集结起来，竭尽全力保护平民，向α星上唯一可能提供庇护的地点——一座名为“环形山阵地”的废弃军事基地撤退。</p><p>在这场惨烈的撤退战中，一个神秘的身影成为了无数幸存者口中的传奇。据多位目击者（多为孩童，其纯真的视角反而更具说服力）描述，一位被称为“归家者”的独行战士加入了抵抗。他如同行走于战场边缘的死神，每一次神出鬼没的狙击，都精准而致命地带走一位高等级的灵裔指挥官或精英战士，极大地延缓了灵裔的追击步伐。正是他一次次的出手，为军队和平民的撤离创造了宝贵的窗口期。他的存在，成为了那片血色地狱中，一抹微弱但坚定的希望之光。</p><p>最终，灵裔彻底占领了α星的所有主要城市及周边富饶地区，财团在该星球的统治体系被连根拔起，宣告了其在此的彻底崩溃。</p><h2 id="历史的十字路口-深远影响与反思" tabindex="-1">历史的十字路口：深远影响与反思 <a class="header-anchor" href="#历史的十字路口-深远影响与反思" aria-label="Permalink to “历史的十字路口：深远影响与反思”">​</a></h2><p>“α星大屠杀”的后果是灾难性的，亦是划时代的。据不完全统计，此次事件共造成数千万人的死伤，其中无辜平民的比例高达七成，这是星际开拓时代以来罕见的人道主义灾难。</p><ul><li><p>对于财团而言，这是敲响其丧钟的致命一击。作为一个仅拥有两颗主要行星的商业帝国，α星的失陷意味着其统治疆域与核心利益瞬间腰斩。这不仅是物质上的巨大损失，更是对其统治合法性与军事威慑力的毁灭性打击。财团不可战胜的神话就此破灭，一个庞大商业帝国的黄昏，自此拉开帷幕。</p></li><li><p>对于灵裔而言，这场胜利的意义则更为复杂。客观上，它以最直接、最暴力的方式，将灵裔这个名字第一次以征服者的姿态，强行铭刻在了星图之上。他们不再是蜷缩于诅咒之地的囚徒，而是一股足以颠覆星系格局的强大势力。然而，这场胜利的底色却是极不光彩的。大屠杀充分暴露了灵裔军队在狂热复仇欲望下无组织、无纪律的原始兽性，证明了他们尚未形成一个成熟、统一的革命纲领。这种野蛮行径，不仅为灵裔在星系间的声誉烙上了难以洗刷的污点，更重要的是，它为灵裔内部的变革提供了血的教训与无可辩驳的理由。正是目睹了这场失控的屠杀，才让领袖星源下定决心，在日后推行铁腕改革，重塑灵裔的社会结构与军事纪律，将这股狂野的复仇力量，锻造成一支真正令人生畏的文明之师。</p></li></ul><p>因此，“α星大屠杀”不仅是一场战争的结束，更是一个十字路口。它标志着财团霸权的衰落，灵裔的正式崛起，以及星源未来改革之路的必然开启。历史的车轮，在这一天，被鲜血浸透，然后轰然转向。</p>',19)),t(r),t(s)])}const P=n(i,[["render",h]]);export{u as __pageData,P as default};
